<?phpdefine("RelativePath", ".");include(RelativePath . "/Common.php");set_time_limit(0);$file_type = "vnd.ms-excel";$name = CCGetSession('nameXls') . "_" . date('d_m_Y');$file_ending = "xls";$filename = $name . "." . $file_ending;header("Content-Type: application/$file_type");header("Content-Disposition: attachment; filename=".$filename);header("Pragma: no-cache");header("Expires: 0");function encabezado($c){	while (list ($clave, $val) = each ($c)){		echo $val . "\t";	}	print("\n");}$SQL = CCGetSession('qryXls');$col = CCGetParam('columnas');$all = CCGetSession('colXls');while (list ($clave, $val) = each ($col)) {	if(array_key_exists($val,$all)){		$campos[$val] = $all[$val];	} }$SQL = str_replace("{SQL_Where}","",$SQL);$SQL = str_replace("{SQL_OrderBy}","",$SQL);//echo $SQL;exit;$db = new clsDBtdf_nuevo();encabezado($campos);$sep = "\t";$db->query($SQL);while($db->next_record()){	//echo $db->f('reg_n_registro') . "<br>";	$schema_insert = "";	while (list($k,$v) = each($campos)){	if(!$db->f($k)){			$schema_insert .= "".$sep;		} else {			if(is_numeric($db->f($k))){				$str = str_replace('.',',',$db->f($k));			}else{					$str = $db->f($k);			}			 $schema_insert .= strtoupper($str).$sep;		}	}	$schema_insert = preg_replace("/\r\n|\n\r|\n|\r/", " ", $schema_insert);	$schema_insert .= "\t";	$schema_insert = trim($schema_insert);	echo($schema_insert);	echo "\n";	reset($campos);}$db->close();?>